'use client';import Link from 'next/link';import { useMemo } from 'react';import { useRouter, useSearchParams } from 'next/navigation';import toast from 'react-hot-toast';import { useErpData } from '@/components/erp/useErpData';import { DataTable } from '@/components/erp/DataTable';import { EmptyState, PageHeader } from '@/components/erp/shared';import { formatCurrency } from '@/lib/utils';
export default function Vendors(){const {data,loading,refresh}=useErpData();const router=useRouter();const params=useSearchParams();const q=params.get('q')||'';const sales=data?.sales||[];const rows=useMemo(()=> (data?.sellers||[]).filter((v:any)=>!q||v.name.toLowerCase().includes(q.toLowerCase())).map((v:any)=>({...v,total:sales.filter((s:any)=>s.sellerId===v.id).reduce((a:number,b:any)=>a+(b.total-b.discount+b.freight),0),count:sales.filter((s:any)=>s.sellerId===v.id).length})),[data,q,sales]);const setQ=(v:string)=>{const n=new URLSearchParams(params.toString());v?n.set('q',v):n.delete('q');router.replace(`/dashboard/vendors?${n}`)};const archive=async(id:string)=>{if(!confirm('Inativar vendedor?'))return;const r=await fetch(`/api/v1/erp/sellers/${id}`,{method:'DELETE'});if(!r.ok)return toast.error('Falha');toast.success('Vendedor inativado');refresh();};
return <div className='space-y-4'><PageHeader title='Vendedores' subtitle='Equipe comercial e comissão.' actions={<Link href='/dashboard/vendors/new' className='underline text-sm'>Novo vendedor</Link>}/><input className='border rounded h-9 px-3' placeholder='Buscar vendedor' value={q} onChange={e=>setQ(e.target.value)}/>{loading?<div className='h-24 bg-white border rounded animate-pulse'/>:!rows.length?<EmptyState title='Sem vendedores' description='Cadastre sua equipe comercial.'/>:<DataTable rows={rows} columns={[{key:'name',label:'Nome',render:(r:any)=><Link href={`/dashboard/vendors/${r.id}`} className='underline'>{r.name}</Link>},{key:'phone',label:'Telefone'},{key:'email',label:'Email'},{key:'commissionRate',label:'Comissão %',render:(r:any)=>r.commissionRate??'-'},{key:'count',label:'# vendas'},{key:'total',label:'Total vendido',render:(r:any)=>formatCurrency(r.total)},{key:'active',label:'Status',render:(r:any)=>r.active?'Ativo':'Inativo'},{key:'actions',label:'Ações',render:(r:any)=><button onClick={()=>archive(r.id)} className='underline text-red-600'>Arquivar</button>}]} />}</div>}
